322	        Some(socket2::Protocol::from(libc::IPPROTO_RAW as i32)),
323	    )
324	    .map_err(|e| format!("raw socket: {}", e))?;
325	    unsafe {
326	        let val: libc::c_int = 1;
327	        libc::setsockopt(
328	            send_sock.as_raw_fd(),
329	            libc::IPPROTO_IP,
330	            libc::IP_HDRINCL,
331	            &val as *const _ as *const libc::c_void,
332	            std::mem::size_of::<libc::c_int>() as libc::socklen_t,
333	        );
334	    }
335	    send_sock
336	        .send_to(packet, &sock_addr)
337	        .map_err(|e| format!("sendto: {}", e))?;
338	
339	    // Listen for TCP response
