348	        .map_err(|e| format!("timeout: {}", e))?;
349	
350	    let mut buf = [0u8; 4096];
351	    let deadline = Instant::now() + timeout;
352	    loop {
353	        let remaining = deadline.saturating_duration_since(Instant::now());
354	        if remaining.is_zero() {
355	            return Ok(false);
356	        }
357	        let _ = listen_sock.set_read_timeout(Some(remaining));
